// Long method: multiple levels of abstraction mixed together
public void processOrder(Order order) {
    // validate
    if (order.getItems().isEmpty()) throw new IllegalArgumentException();
    if (order.getCustomer() == null) throw new IllegalArgumentException();

    // calculate total
    double total = 0;
    for (Item item : order.getItems()) {
        total += item.getPrice() * item.getQty();
    }
    if (order.hasPromoCode()) total *= 0.9;

    // persist and notify
    order.setTotal(total);
    repository.save(order);
    emailService.send(order.getCustomer().getEmail(), "Your order: " + total);
}

// After Extract Method
public void processOrder(Order order) {
    validate(order);
    order.setTotal(calculateTotal(order));
    repository.save(order);
    notifyCustomer(order);
}

