// Feature Envy: calculateShipping lives in Order but works on Address fields
class Order {
    private Address shippingAddress;

    public double calculateShipping() {
        // envies Address — all this logic belongs in Address or ShippingCalculator
        if (shippingAddress.getCountry().equals("US")) {
            if (shippingAddress.getState().equals("CA")) return 5.0;
            return 8.0;
        }
        return 25.0;
    }
}

