// Type-code switch — grows with every new bird type
class Bird {
    BirdType type;
    double getSpeed() {
        return switch (type) {
            case EUROPEAN  -> baseSpeed();
            case AFRICAN   -> baseSpeed() - loadFactor() * numberOfCoconuts;
            case NORWEGIAN -> isNailed ? 0 : baseSpeed() + 10.0;
        };
    }
}

// After: Replace Conditional with Polymorphism
abstract class Bird {
    abstract double getSpeed();
}

class EuropeanBird extends Bird {
    double getSpeed() { return baseSpeed(); }
}

class AfricanBird extends Bird {
    double getSpeed() { return baseSpeed() - loadFactor() * numberOfCoconuts; }
}

class NorwegianBird extends Bird {
    boolean isNailed;
    double getSpeed() { return isNailed ? 0 : baseSpeed() + 10.0; }
}
